class CascadesJoinSearchBenchmarkTest {

	@Test
	void parameterMatrixBuildsEveryLegalShapeWithoutPlanningDenseCases() {
		int cases = 0;
		for (int factors : CascadesJoinSearchBenchmark.FACTOR_COUNTS) {
			for (GraphShape shape : CascadesJoinSearchBenchmark.SHAPES) {
				for (int predicates : CascadesJoinSearchBenchmark.PREDICATE_COUNTS) {
					SyntheticCase syntheticCase = CascadesJoinSearchBenchmark.syntheticCase(factors, shape,
							predicates);
					assertEquals(factors, countFactors(syntheticCase.root()));
					assertEquals(predicates, countFilters(syntheticCase.root()));
					assertEquals(expectedEdges(factors, shape), syntheticCase.topologyEdgeCount());
					cases += CascadesJoinSearchBenchmark.SEARCH_MODES.length;
				}
			}
		}
		assertEquals(150, cases);
	}

	@Test
	void fourFactorAutoSmokeUsesRealScopedPlannerDeterministically() {
		PlanningObservation first = CascadesJoinSearchBenchmark.planOnce(4, GraphShape.CHAIN, 0,
				OptimizationGoal.SearchMode.AUTO);
		PlanningObservation second = CascadesJoinSearchBenchmark.planOnce(4, GraphShape.CHAIN, 0,
				OptimizationGoal.SearchMode.AUTO);

		assertEquals(first, second);
		assertTrue(first.winnerPresent());
		assertTrue(first.partitionProbes() > 0L, first.toString());
		assertTrue(first.candidateEvaluations() > 0L);
		assertTrue(first.retainedCandidateHighWater() > 0L);
		assertTrue(first.memoGroups() >= 4);
		assertTrue(first.exportedJoinRecipes() > 0);
	}

	@Test
	void twelveFactorCliqueAutoIsDeterministicLegalAndBounded() {
		SyntheticCase syntheticCase = CascadesJoinSearchBenchmark.syntheticCase(12, GraphShape.CLIQUE, 0);
		PlannerState state = new PlannerState();
		state.factors = 12;
		state.shape = GraphShape.CLIQUE;
		state.predicateCount = 0;
		state.searchMode = OptimizationGoal.SearchMode.AUTO;
		state.setupTrial();

		state.setupInvocation();
		CascadesPlan first = state.optimize();
		state.setupInvocation();
		CascadesPlan second = state.optimize();

		TupleExpr firstPlan = first.tupleExpr().orElseThrow();
		TupleExpr secondPlan = second.tupleExpr().orElseThrow();
		SearchCounterSnapshot counters = first.searchStatus().counters();
		SearchRetentionSnapshot retention = first.searchStatus().retention();
		assertAll(
				() -> assertEquals(OptimizationCompleteness.BUDGET_EXHAUSTED, first.completeness(),
						first.diagnostics().toString()),
				() -> assertEquals(first.completeness(), second.completeness()),
				() -> assertEquals(first.searchStatus().limitCauses(), second.searchStatus().limitCauses()),
				() -> assertEquals(counters, second.searchStatus().counters()),
				() -> assertEquals(retention, second.searchStatus().retention()),
				() -> assertEquals(first.winner().orElseThrow().physicalOperatorId(),
						second.winner().orElseThrow().physicalOperatorId()),
				() -> assertEquals(planFingerprint(firstPlan), planFingerprint(secondPlan)),
				() -> assertEquals(factorBag(syntheticCase.root()), factorBag(firstPlan),
						"bounded AUTO must retain every clique factor exactly once"),
				() -> assertEquals(12, countFactors(firstPlan)),
				() -> assertTrue(first.searchStatus().limitCauses().contains(OptimizationLimitCause.PARTITION_PROBES),
						first.diagnostics().toString()),
				() -> assertFalse(first.searchStatus().limitCauses().contains(OptimizationLimitCause.DEADLINE)),
				() -> assertFalse(first.searchStatus()
						.limitCauses()
						.contains(OptimizationLimitCause.UNSUPPORTED_REPRESENTATION)),
				() -> assertTrue(counters.ruleWork() > 0L && counters.ruleWork() <= SearchLimits.AUTO.ruleWork()),
				() -> assertEquals(0L, counters.dphypPairProbes(),
						"the core benchmark route intentionally has no store-specific DPhyp contributor"),
				() -> assertEquals(SearchLimits.AUTO.partitionProbes(), counters.partitionProbes()),
				() -> assertTrue(counters.candidateEvaluations() > 0L
						&& counters.candidateEvaluations() <= SearchLimits.AUTO.candidateEvaluations()),
				() -> assertTrue(counters.predicateProbes() <= SearchLimits.AUTO.predicateProbes()),
				() -> assertTrue(retention.currentRetainedCandidates() <= SearchLimits.AUTO.retainedCandidates()),
				() -> assertTrue(retention.retainedCandidateHighWaterMark() <= SearchLimits.AUTO.retainedCandidates()),
				() -> assertTrue(retention.frontierHighWaterMark() <= SearchLimits.AUTO.frontierCandidates()));
	}

	private static int countFilters(TupleExpr expression) {
		int filters = 0;
		TupleExpr current = expression;
		while (current instanceof Filter filter) {
			filters++;
			current = filter.getArg();
		}
		return filters;
	}

	private static int countFactors(TupleExpr expression) {
		TupleExpr current = expression;
		while (current instanceof Filter filter) {
			current = filter.getArg();
		}
		if (current instanceof Join join) {
			return countFactors(join.getLeftArg()) + countFactors(join.getRightArg());
		}
		return 1;
	}

	private static Map<String, Long> factorBag(TupleExpr expression) {
		Map<String, Long> factors = new TreeMap<>();
		collectFactors(expression, factors);
		return factors;
	}

	private static void collectFactors(TupleExpr expression, Map<String, Long> factors) {
		if (expression instanceof Join join) {
			collectFactors(join.getLeftArg(), factors);
			collectFactors(join.getRightArg(), factors);
			return;
		}
		if (!(expression instanceof StatementPattern pattern) || !pattern.getPredicateVar().hasValue()) {
			throw new AssertionError("Unexpected dense-clique factor: " + expression);
		}
		factors.merge(pattern.getPredicateVar().getValue().stringValue(), 1L, Long::sum);
	}

	private static String planFingerprint(TupleExpr expression) {
		if (expression instanceof Join join) {
			return "join(" + planFingerprint(join.getLeftArg()) + ',' + planFingerprint(join.getRightArg()) + ')';
		}
		if (expression instanceof StatementPattern pattern && pattern.getPredicateVar().hasValue()) {
			return pattern.getPredicateVar().getValue().stringValue();
		}
		throw new AssertionError("Unexpected dense-clique factor: " + expression);
	}

	private static int expectedEdges(int factors, GraphShape shape) {
		return switch (shape) {
		case CHAIN, STAR -> factors - 1;
		case CYCLE -> factors;
		case CLIQUE -> factors * (factors - 1) / 2;
		case DISCONNECTED -> 0;
		};
	}
}
